#pragma warning disable CS1591, CS1573
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class RetrievalController : ControllerBase
    {
        private readonly global::IRetrievalService iRetrievalService;
        public RetrievalController(global::IRetrievalService iRetrievalService)
        {
            this.iRetrievalService = iRetrievalService;
        }
        [Route("RetrieveUser/{id}")]
        [HttpGet]
        public string RetrieveUser([FromRoute] string id)
        {
            return this.iRetrievalService.RetrieveUser(id);
        }
    }
}
